#include <iostream>#include <string>using namespace std;//  Função para mostrar mensagem inicialvoid mostrarBoasVindas(string nome) {    cout << "Bem-vindo(a), " << nome << "! 😄" << endl;}//  Função para mostrar menuvoid mostrarMenu() {    cout << endl;    cout << "1 - Correr atras do rato" << endl;    cout << "2 - Comer queijo" << endl;    cout << "3 - Dormir" << endl;    cout << "0 - Sair" << endl;}//  Função para processar escolhavoid processarEscolha(int escolha) {    if (escolha == 1) {        cout << "Voce correu atras do rato! 🏃" << endl;    }    else if (escolha == 2) {        cout << "Voce comeu queijo 🧀" << endl;    }    else if (escolha == 3) {        cout << "Voce foi dormir 😴" << endl;    }    else if (escolha == 0) {        cout << "Saindo do jogo... 👋" << endl;    }    else {        cout << "Opcao invalida 😅" << endl;    }}int main() {    string nome;    int escolha;    cout << "Digite o teu nome: ";    cin >> nome;    mostrarBoasVindas(nome);    do {        mostrarMenu();        cout << "Opcao: ";        cin >> escolha;        processarEscolha(escolha);    } while (escolha != 0);    return 0;}